CREATE OR REPLACE FUNCTION fpa_dep_item_dot_real (as_depno char,ai_seqno integer,adt_date timestamp(0)) RETURNS char AS $body$
DECLARE

  li_seq_no sc_dep_m_creditor_item.seq_no%type;
  ls_return char(1);
  li_month sc_kep_t_monthly_receive_det.receive_month%type;
  ldt_date timestamp(0);

BEGIN
  ldt_date :=PKA_SRV_DATETIME.fp_LastDayOfMonth(adt_date)+1;
  select  max(seq_no) into STRICT li_seq_no
  from    sc_dep_m_creditor_item
  where (deposit_account_no = as_depno)
  and (sc_dep_m_creditor_item.operate_date <= ldt_date);

  if  ai_seqno = li_seq_no then
      ls_return := '0';
  else
      ls_return := '1';
  end if;

return ls_return;
exception when others then CALL spa_dberror('FPA_DEP_ITEM_DOT_REAL');return null;
END;
$body$
LANGUAGE PLPGSQL
